#include <stdio.h>

typedef struct {
    char name[16];
    int age;
} Person;

void stableSelectByAge(Person a[], int n) {
    for (int i = 0; i < n - 1; ++i) {
        int min = i;
        for (int j = i + 1; j < n; ++j) {
            if (a[j].age < a[min].age) {
                min = j;
            }
        }
        Person temp = a[min];
        for (int k = min; k > i; --k) {
            a[k] = a[k - 1];
        }
        a[i] = temp;
    }
}
